var COURSE_PL_TR = [{day: 1, title: `Pierwsze powitania`, title_native: `İlk selamlaşmalar`, focus: `Nauczysz się witać i żegnać w Stambule, w hotelu, sklepie lub kawiarni. To pierwszy krok do uprzejmej rozmowy w Turcji.`, vocab: [{tr: `merhaba`, pl: `cześć / dzień dobry`, ipa: `mer-ha-ba`},{tr: `selam`, pl: `cześć`, ipa: `se-lam`},{tr: `günaydın`, pl: `dzień dobry rano`, ipa: `gy-naj-dyn`},{tr: `iyi akşamlar`, pl: `dobry wieczór`, ipa: `i-ji ak-szam-lar`},{tr: `iyi geceler`, pl: `dobranoc`, ipa: `i-ji ge-dże-ler`},{tr: `hoşça kal`, pl: `trzymaj się / do widzenia`, ipa: `hosz-cza kal`},{tr: `görüşürüz`, pl: `do zobaczenia`, ipa: `gy-ry-szy-ryz`},{tr: `lütfen`, pl: `proszę`, ipa: `lyt-fen`},{tr: `teşekkürler`, pl: `dziękuję`, ipa: `te-szek-kyr-ler`},{tr: `evet`, pl: `tak`, ipa: `e-wet`}], phrases: [{tr: `Merhaba.`, pl: `Dzień dobry.`, ipa: `mer-ha-ba`},{tr: `Günaydın.`, pl: `Dzień dobry rano.`, ipa: `gy-naj-dyn`},{tr: `İyi akşamlar.`, pl: `Dobry wieczór.`, ipa: `i-ji ak-szam-lar`},{tr: `Teşekkürler.`, pl: `Dziękuję.`, ipa: `te-szek-kyr-ler`},{tr: `Görüşürüz.`, pl: `Do zobaczenia.`, ipa: `gy-ry-szy-ryz`},{tr: `Hoşça kal.`, pl: `Do widzenia.`, ipa: `hosz-cza kal`}], grammar: `W tureckim często używa się gotowych form grzecznościowych, które działają w wielu sytuacjach. „Merhaba” jest bezpieczne prawie zawsze: w hotelu, sklepie, taksówce i przy pierwszym spotkaniu. Tureckie „r” jest wyraźne, ale nie trzeba go przesadnie rolować.`, practice: [`Powiedz po turecku „Dzień dobry” do recepcjonisty.`,`Powiedz „Dziękuję” po zakupie kawy.`,`Pożegnaj się z kimś, mówiąc „Do zobaczenia”.`,`Wybierz, kiedy użyjesz „günaydın”, a kiedy „iyi akşamlar”.`,`Przeczytaj na głos wszystkie słowa z VOCAB trzy razy.`]},{day: 2, title: `Tak, nie i uprzejme reakcje`, title_native: `Evet, hayır ve nazik cevaplar`, focus: `Dziś nauczysz się krótkich odpowiedzi potrzebnych w podróży po Ankarze lub Izmirze. Dzięki nim łatwiej odpowiesz w sklepie, muzeum albo podczas kontroli biletu.`, vocab: [{tr: `hayır`, pl: `nie`, ipa: `ha-jyr`},{tr: `tamam`, pl: `dobrze / okej`, ipa: `ta-mam`},{tr: `pardon`, pl: `przepraszam`, ipa: `par-don`},{tr: `özür dilerim`, pl: `przepraszam`, ipa: `y-zyr di-le-rim`},{tr: `bir şey değil`, pl: `nie ma za co`, ipa: `bir szej de-jil`},{tr: `iyi`, pl: `dobrze`, ipa: `i-ji`},{tr: `kötü`, pl: `źle`, ipa: `ky-ty`},{tr: `belki`, pl: `może`, ipa: `bel-ki`},{tr: `şimdi`, pl: `teraz`, ipa: `szim-di`},{tr: `sonra`, pl: `później`, ipa: `son-ra`}], phrases: [{tr: `Evet, lütfen.`, pl: `Tak, proszę.`, ipa: `e-wet lyt-fen`},{tr: `Hayır, teşekkürler.`, pl: `Nie, dziękuję.`, ipa: `ha-jyr te-szek-kyr-ler`},{tr: `Tamam.`, pl: `Okej.`, ipa: `ta-mam`},{tr: `Pardon.`, pl: `Przepraszam.`, ipa: `par-don`},{tr: `Özür dilerim.`, pl: `Przepraszam.`, ipa: `y-zyr di-le-rim`},{tr: `Bir şey değil.`, pl: `Nie ma za co.`, ipa: `bir szej de-jil`}], grammar: `„Lütfen” może znaczyć „proszę” jako uprzejma prośba, a „teşekkürler” jako szybkie „dzięki”. Po turecku krótkie odpowiedzi są bardzo naturalne, ale warto dodać uprzejmy ton. „Pardon” użyjesz, gdy chcesz przejść, zwrócić uwagę albo przeprosić za drobny błąd.`, practice: [`Odpowiedz po turecku „Nie, dziękuję”.`,`Powiedz „Tak, proszę” w kawiarni.`,`Przeproś kogoś, gdy przypadkiem staniesz mu na drodze.`,`Powiedz „Okej” po usłyszeniu ceny.`,`Ułóż krótką scenkę: sprzedawca pyta, ty odpowiadasz „Hayır, teşekkürler”.`]},{day: 3, title: `Przedstawianie się`, title_native: `Kendini tanıtma`, focus: `Nauczysz się mówić, jak masz na imię i skąd jesteś. To przyda się przy poznawaniu ludzi w hostelu, na wycieczce po Kapadocji lub przy wspólnym stoliku.`, vocab: [{tr: `ben`, pl: `ja`, ipa: `ben`},{tr: `sen`, pl: `ty`, ipa: `sen`},{tr: `ad`, pl: `imię`, ipa: `ad`},{tr: `adım`, pl: `moje imię`, ipa: `a-dym`},{tr: `Polonya`, pl: `Polska`, ipa: `po-lon-ja`},{tr: `Türkiyе`, pl: `Turcja`, ipa: `tyr-ki-je`},{tr: `nereli`, pl: `skąd`, ipa: `ne-re-li`},{tr: `memnun`, pl: `zadowolony`, ipa: `mem-nun`},{tr: `tanışmak`, pl: `poznawać się`, ipa: `ta-nysz-mak`},{tr: `arkadaş`, pl: `przyjaciel / znajomy`, ipa: `ar-ka-dasz`}], phrases: [{tr: `Benim adım Anna.`, pl: `Mam na imię Anna.`, ipa: `be-nim a-dym an-na`},{tr: `Adınız ne?`, pl: `Jak ma pan/pani na imię?`, ipa: `a-dy-nyz ne`},{tr: `Ben Polonyalıyım.`, pl: `Jestem Polakiem/Polką.`, ipa: `ben po-lon-ja-ly-jym`},{tr: `Nerelisiniz?`, pl: `Skąd pan/pani jest?`, ipa: `ne-re-li-si-niz`},{tr: `Memnun oldum.`, pl: `Miło mi.`, ipa: `mem-nun ol-dum`},{tr: `Ben de memnun oldum.`, pl: `Mnie też miło.`, ipa: `ben de mem-nun ol-dum`}], grammar: `W tureckim często dodaje się końcówki do słowa zamiast używać osobnego czasownika „jestem”. „Polonyalıyım” znaczy „jestem z Polski / jestem Polakiem lub Polką”. W formach grzecznych często pojawia się końcówka „-siniz”, jak w „Nerelisiniz?”.`, practice: [`Powiedz po turecku swoje imię: „Benim adım...”.`,`Zapytaj uprzejmie kogoś o imię.`,`Powiedz, że jesteś z Polski.`,`Odpowiedz „Miło mi” po przedstawieniu się.`,`Przećwicz dialog dwóch osób poznających się w hostelu.`]},{day: 4, title: `Liczby od 0 do 20`, title_native: `Sıfırdan yirmiye sayılar`, focus: `Dziś poznasz liczby potrzebne przy zakupach, biletach i adresach. W Stambule liczby usłyszysz wszędzie: w tramwaju, na bazarze i przy kasie.`, vocab: [{tr: `sıfır`, pl: `zero`, ipa: `sy-fyr`},{tr: `bir`, pl: `jeden`, ipa: `bir`},{tr: `iki`, pl: `dwa`, ipa: `i-ki`},{tr: `üç`, pl: `trzy`, ipa: `ycz`},{tr: `dört`, pl: `cztery`, ipa: `dyrt`},{tr: `beş`, pl: `pięć`, ipa: `besz`},{tr: `altı`, pl: `sześć`, ipa: `al-ty`},{tr: `yedi`, pl: `siedem`, ipa: `je-di`},{tr: `sekiz`, pl: `osiem`, ipa: `se-kiz`},{tr: `on`, pl: `dziesięć`, ipa: `on`}], phrases: [{tr: `Bir tane lütfen.`, pl: `Jedną sztukę poproszę.`, ipa: `bir ta-ne lyt-fen`},{tr: `İki bilet lütfen.`, pl: `Dwa bilety poproszę.`, ipa: `i-ki bi-let lyt-fen`},{tr: `Üç kahve istiyorum.`, pl: `Chcę trzy kawy.`, ipa: `ycz kah-we is-ti-jo-rum`},{tr: `Bu kaç lira?`, pl: `Ile to lir?`, ipa: `bu kacz li-ra`},{tr: `On lira mı?`, pl: `Dziesięć lir?`, ipa: `on li-ra my`},{tr: `Bir dakika.`, pl: `Chwileczkę.`, ipa: `bir da-ki-ka`}], grammar: `Liczby w tureckim nie zmieniają formy rzeczownika tak jak w polskim. „İki bilet” to dosłownie „dwa bilet”, bez specjalnej liczby mnogiej. To ułatwia mówienie: liczba + rzeczownik wystarcza w wielu sytuacjach.`, practice: [`Policz po turecku od 0 do 10.`,`Zamów dwa bilety.`,`Powiedz „jedną sztukę poproszę”.`,`Zapytaj „Ile to lir?”.`,`Napisz liczby 11–20 z pomocą słownika i przeczytaj je głośno.`]},{day: 5, title: `Podstawowe pytania`, title_native: `Temel sorular`, focus: `Nauczysz się zadawać krótkie pytania, które ratują sytuację w podróży. Przydadzą się na lotnisku w Antalyi, w metrze i w małym sklepie.`, vocab: [{tr: `ne`, pl: `co`, ipa: `ne`},{tr: `kim`, pl: `kto`, ipa: `kim`},{tr: `nerede`, pl: `gdzie`, ipa: `ne-re-de`},{tr: `ne zaman`, pl: `kiedy`, ipa: `ne za-man`},{tr: `nasıl`, pl: `jak`, ipa: `na-syl`},{tr: `kaç`, pl: `ile`, ipa: `kacz`},{tr: `hangi`, pl: `który`, ipa: `han-gi`},{tr: `burada`, pl: `tutaj`, ipa: `bu-ra-da`},{tr: `orada`, pl: `tam`, ipa: `o-ra-da`},{tr: `yakın`, pl: `blisko`, ipa: `ja-kyn`}], phrases: [{tr: `Bu ne?`, pl: `Co to jest?`, ipa: `bu ne`},{tr: `Nerede?`, pl: `Gdzie?`, ipa: `ne-re-de`},{tr: `Tuvalet nerede?`, pl: `Gdzie jest toaleta?`, ipa: `tu-wa-let ne-re-de`},{tr: `Ne zaman?`, pl: `Kiedy?`, ipa: `ne za-man`},{tr: `Kaç para?`, pl: `Ile kosztuje?`, ipa: `kacz pa-ra`},{tr: `Nasıl gidilir?`, pl: `Jak się tam idzie/jedzie?`, ipa: `na-syl gi-di-lir`}], grammar: `Tureckie pytania często powstają przez dodanie słowa pytającego, bez zmiany szyku na taki jak w polskim. „Tuvalet nerede?” dosłownie znaczy „Toaleta gdzie?”. W mowie podróżnej to całkowicie naturalne i bardzo przydatne.`, practice: [`Zapytaj po turecku „Gdzie jest toaleta?”.`,`Zapytaj „Co to jest?” na targu.`,`Powiedz „Kiedy?” przy pytaniu o odjazd autobusu.`,`Zapytaj „Ile kosztuje?”.`,`Połącz trzy pytania w krótką rozmowę z pracownikiem informacji.`]},{day: 6, title: `Na lotnisku`, title_native: `Havalimanında`, focus: `Dziś ćwiczysz słowa potrzebne po przylocie do Stambułu lub Ankary. Nauczysz się pytać o bagaż, paszport i wyjście.`, vocab: [{tr: `havalimanı`, pl: `lotnisko`, ipa: `ha-wa-li-ma-ny`},{tr: `uçak`, pl: `samolot`, ipa: `u-czak`},{tr: `pasaport`, pl: `paszport`, ipa: `pa-sa-port`},{tr: `bagaj`, pl: `bagaż`, ipa: `ba-gaj`},{tr: `çıkış`, pl: `wyjście`, ipa: `czy-kysz`},{tr: `giriş`, pl: `wejście`, ipa: `gi-risz`},{tr: `kontrol`, pl: `kontrola`, ipa: `kon-trol`},{tr: `bilet`, pl: `bilet`, ipa: `bi-let`},{tr: `kapı`, pl: `bramka / drzwi`, ipa: `ka-py`},{tr: `gecikme`, pl: `opóźnienie`, ipa: `ge-dżik-me`}], phrases: [{tr: `Pasaportum burada.`, pl: `Mój paszport jest tutaj.`, ipa: `pa-sa-por-tum bu-ra-da`},{tr: `Bagaj nerede?`, pl: `Gdzie jest bagaż?`, ipa: `ba-gaj ne-re-de`},{tr: `Çıkış nerede?`, pl: `Gdzie jest wyjście?`, ipa: `czy-kysz ne-re-de`},{tr: `Biletim var.`, pl: `Mam bilet.`, ipa: `bi-le-tim war`},{tr: `Uçak gecikti mi?`, pl: `Czy samolot jest opóźniony?`, ipa: `u-czak ge-dżik-ti mi`},{tr: `Kapı kaç?`, pl: `Która bramka?`, ipa: `ka-py kacz`}], grammar: `Końcówka „-im” może oznaczać „mój/moja/moje”, jak w „biletim” i „pasaportum”. Samogłoska w końcówce zmienia się według harmonii samogłosek, ale na początku wystarczy zapamiętać całe przydatne formy. „Var” znaczy „jest / mam”, zależnie od kontekstu.`, practice: [`Powiedz, że masz bilet.`,`Zapytaj, gdzie jest wyjście.`,`Zapytaj o bagaż.`,`Powiedz, że paszport jest tutaj.`,`Odegraj krótką scenkę przy kontroli paszportowej.`]},{day: 7, title: `Hotel i meldunek`, title_native: `Otel ve giriş işlemleri`, focus: `Nauczysz się zameldować w hotelu w Izmirze albo pensjonacie w Kapadocji. Będziesz umieć powiedzieć, że masz rezerwację i zapytać o pokój.`, vocab: [{tr: `otel`, pl: `hotel`, ipa: `o-tel`},{tr: `rezervasyon`, pl: `rezerwacja`, ipa: `re-zer-wa-sjon`},{tr: `oda`, pl: `pokój`, ipa: `o-da`},{tr: `anahtar`, pl: `klucz`, ipa: `a-nah-tar`},{tr: `kimlik`, pl: `dokument tożsamości`, ipa: `kim-lik`},{tr: `gece`, pl: `noc`, ipa: `ge-dże`},{tr: `kahvaltı`, pl: `śniadanie`, ipa: `kah-wal-ty`},{tr: `asansör`, pl: `winda`, ipa: `a-san-syr`},{tr: `resepsiyon`, pl: `recepcja`, ipa: `re-sep-sjon`},{tr: `ücret`, pl: `opłata`, ipa: `y-dżret`}], phrases: [{tr: `Rezervasyonum var.`, pl: `Mam rezerwację.`, ipa: `re-zer-wa-sjo-num war`},{tr: `Bir odam var mı?`, pl: `Czy mam pokój?`, ipa: `bir o-dam war my`},{tr: `Kimliğim burada.`, pl: `Mój dokument jest tutaj.`, ipa: `kim-li-im bu-ra-da`},{tr: `Kahvaltı dahil mi?`, pl: `Czy śniadanie jest wliczone?`, ipa: `kah-wal-ty da-hil mi`},{tr: `Anahtar lütfen.`, pl: `Klucz poproszę.`, ipa: `a-nah-tar lyt-fen`},{tr: `Asansör nerede?`, pl: `Gdzie jest winda?`, ipa: `a-san-syr ne-re-de`}], grammar: `„Var mı?” tworzy pytanie „czy jest / czy mam?”. „Rezervasyonum var” oznacza „mam rezerwację”, a „Rezervasyonum var mı?” może znaczyć „czy mam rezerwację?”. To bardzo praktyczna konstrukcja w hotelach i biurach.`, practice: [`Powiedz w recepcji, że masz rezerwację.`,`Zapytaj, czy śniadanie jest wliczone.`,`Poproś o klucz.`,`Zapytaj, gdzie jest winda.`,`Ułóż dialog meldunkowy z pięciu krótkich zdań.`]},{day: 8, title: `Pokój i problemy w hotelu`, title_native: `Oda ve otel sorunları`, focus: `Dziś nauczysz się mówić o pokoju, klimatyzacji, Wi-Fi i drobnych problemach. To przydatne w hotelu w upalnej Antalyi lub nad Morzem Egejskim.`, vocab: [{tr: `yatak`, pl: `łóżko`, ipa: `ja-tak`},{tr: `banyo`, pl: `łazienka`, ipa: `ban-jo`},{tr: `havlu`, pl: `ręcznik`, ipa: `haw-lu`},{tr: `klima`, pl: `klimatyzacja`, ipa: `kli-ma`},{tr: `internet`, pl: `internet`, ipa: `in-ter-net`},{tr: `şifre`, pl: `hasło`, ipa: `szyf-re`},{tr: `sıcak`, pl: `gorący`, ipa: `sy-dżak`},{tr: `soğuk`, pl: `zimny`, ipa: `so-uk`},{tr: `çalışmıyor`, pl: `nie działa`, ipa: `cza-lysz-my-jor`},{tr: `temiz`, pl: `czysty`, ipa: `te-miz`}], phrases: [{tr: `İnternet şifresi nedir?`, pl: `Jakie jest hasło do internetu?`, ipa: `in-ter-net szyf-re-si ne-dir`},{tr: `Klima çalışmıyor.`, pl: `Klimatyzacja nie działa.`, ipa: `kli-ma cza-lysz-my-jor`},{tr: `Oda temiz mi?`, pl: `Czy pokój jest czysty?`, ipa: `o-da te-miz mi`},{tr: `Havlu alabilir miyim?`, pl: `Czy mogę dostać ręcznik?`, ipa: `haw-lu a-la-bi-lir mi-jim`},{tr: `Banyo nerede?`, pl: `Gdzie jest łazienka?`, ipa: `ban-jo ne-re-de`},{tr: `Su sıcak değil.`, pl: `Woda nie jest gorąca.`, ipa: `su sy-dżak de-jil`}], grammar: `„Değil” oznacza „nie jest”, a „çalışmıyor” znaczy „nie działa”. W tureckim przeczenie często jest częścią czasownika, jak w „çalışmıyor”. W podróży warto zapamiętać całe zdanie „... çalışmıyor”, bo można je łączyć z wieloma rzeczami.`, practice: [`Powiedz, że klimatyzacja nie działa.`,`Zapytaj o hasło do internetu.`,`Poproś o ręcznik.`,`Powiedz, że woda nie jest gorąca.`,`Wymień trzy rzeczy w pokoju po turecku.`]},{day: 9, title: `Kawa, herbata i szybkie zamówienia`, title_native: `Kahve, çay ve hızlı siparişler`, focus: `Nauczysz się zamawiać napoje w tureckiej kawiarni. To idealne na pierwszy poranek w Stambule albo przerwę przy promenadzie w Izmirze.`, vocab: [{tr: `kahve`, pl: `kawa`, ipa: `kah-we`},{tr: `çay`, pl: `herbata`, ipa: `czaj`},{tr: `su`, pl: `woda`, ipa: `su`},{tr: `süt`, pl: `mleko`, ipa: `syt`},{tr: `şeker`, pl: `cukier`, ipa: `sze-ker`},{tr: `bardak`, pl: `szklanka`, ipa: `bar-dak`},{tr: `fincan`, pl: `filiżanka`, ipa: `fin-dżan`},{tr: `küçük`, pl: `mały`, ipa: `ky-czyk`},{tr: `büyük`, pl: `duży`, ipa: `by-jyk`},{tr: `sipariş`, pl: `zamówienie`, ipa: `si-pa-risz`}], phrases: [{tr: `Bir çay lütfen.`, pl: `Herbatę poproszę.`, ipa: `bir czaj lyt-fen`},{tr: `Bir kahve istiyorum.`, pl: `Chcę kawę.`, ipa: `bir kah-we is-ti-jo-rum`},{tr: `Şekersiz lütfen.`, pl: `Bez cukru proszę.`, ipa: `sze-ker-siz lyt-fen`},{tr: `Sütlü kahve var mı?`, pl: `Czy jest kawa z mlekiem?`, ipa: `syt-ly kah-we war my`},{tr: `Bir su alabilir miyim?`, pl: `Czy mogę dostać wodę?`, ipa: `bir su a-la-bi-lir mi-jim`},{tr: `Hesap lütfen.`, pl: `Rachunek poproszę.`, ipa: `he-sap lyt-fen`}], grammar: `Końcówka „-siz” oznacza „bez”, jak w „şekersiz” — bez cukru. Końcówka „-lü” lub „-lı” często oznacza „z czymś”, jak „sütlü” — z mlekiem. To bardzo przydatne przy jedzeniu i napojach.`, practice: [`Zamów herbatę po turecku.`,`Poproś kawę bez cukru.`,`Zapytaj, czy jest kawa z mlekiem.`,`Poproś o wodę.`,`Zakończ zamówienie słowami „Hesap lütfen”.`]},{day: 10, title: `Śniadanie po turecku`, title_native: `Türk kahvaltısı`, focus: `Dziś poznasz słowa związane z tureckim śniadaniem. Przydadzą się w hotelu, kawiarni i małej restauracji w Bursie.`, vocab: [{tr: `kahvaltı`, pl: `śniadanie`, ipa: `kah-wal-ty`},{tr: `ekmek`, pl: `chleb`, ipa: `ek-mek`},{tr: `peynir`, pl: `ser`, ipa: `pej-nir`},{tr: `zeytin`, pl: `oliwki`, ipa: `zej-tin`},{tr: `yumurta`, pl: `jajko`, ipa: `ju-mur-ta`},{tr: `bal`, pl: `miód`, ipa: `bal`},{tr: `tereyağı`, pl: `masło`, ipa: `te-re-ja-y`},{tr: `domates`, pl: `pomidor`, ipa: `do-ma-tes`},{tr: `salatalık`, pl: `ogórek`, ipa: `sa-la-ta-lyk`},{tr: `menemen`, pl: `jajecznica z warzywami`, ipa: `me-ne-men`}], phrases: [{tr: `Kahvaltı istiyorum.`, pl: `Chcę śniadanie.`, ipa: `kah-wal-ty is-ti-jo-rum`},{tr: `Menemen var mı?`, pl: `Czy jest menemen?`, ipa: `me-ne-men war my`},{tr: `Ekmek alabilir miyim?`, pl: `Czy mogę dostać chleb?`, ipa: `ek-mek a-la-bi-lir mi-jim`},{tr: `Peynir istemiyorum.`, pl: `Nie chcę sera.`, ipa: `pej-nir is-te-mi-jo-rum`},{tr: `Bir yumurta lütfen.`, pl: `Jedno jajko poproszę.`, ipa: `bir ju-mur-ta lyt-fen`},{tr: `Çay dahil mi?`, pl: `Czy herbata jest wliczona?`, ipa: `czaj da-hil mi`}], grammar: `„İstiyorum” znaczy „chcę”, a „istemiyorum” znaczy „nie chcę”. To jedna z najważniejszych par w codziennym tureckim. Możesz powiedzieć „Kahve istiyorum” albo „Peynir istemiyorum”, zachowując prosty szyk.`, practice: [`Powiedz, że chcesz śniadanie.`,`Zapytaj, czy jest menemen.`,`Powiedz, że nie chcesz sera.`,`Poproś o jedno jajko.`,`Ułóż własne śniadaniowe zamówienie z trzema produktami.`]},{day: 11, title: `Restauracja i menu`, title_native: `Restoran ve menü`, focus: `Nauczysz się czytać menu i zamawiać proste dania w restauracji. To przydatne przy kolacji w Stambule, Ankarze lub nad morzem.`, vocab: [{tr: `restoran`, pl: `restauracja`, ipa: `res-to-ran`},{tr: `menü`, pl: `menu`, ipa: `me-ny`},{tr: `yemek`, pl: `jedzenie / danie`, ipa: `je-mek`},{tr: `çorba`, pl: `zupa`, ipa: `czor-ba`},{tr: `et`, pl: `mięso`, ipa: `et`},{tr: `tavuk`, pl: `kurczak`, ipa: `ta-wuk`},{tr: `balık`, pl: `ryba`, ipa: `ba-lyk`},{tr: `pilav`, pl: `ryż`, ipa: `pi-law`},{tr: `salata`, pl: `sałatka`, ipa: `sa-la-ta`},{tr: `tatlı`, pl: `deser / słodki`, ipa: `tat-ly`}], phrases: [{tr: `Menü alabilir miyim?`, pl: `Czy mogę dostać menu?`, ipa: `me-ny a-la-bi-lir mi-jim`},{tr: `Ne tavsiye edersiniz?`, pl: `Co pan/pani poleca?`, ipa: `ne taw-si-je e-der-si-niz`},{tr: `Tavuk istiyorum.`, pl: `Chcę kurczaka.`, ipa: `ta-wuk is-ti-jo-rum`},{tr: `Balık var mı?`, pl: `Czy jest ryba?`, ipa: `ba-lyk war my`},{tr: `Çorba lütfen.`, pl: `Zupę poproszę.`, ipa: `czor-ba lyt-fen`},{tr: `Tatlı istemiyorum.`, pl: `Nie chcę deseru.`, ipa: `tat-ly is-te-mi-jo-rum`}], grammar: `„Alabilir miyim?” oznacza „czy mogę dostać / wziąć?”. To bardzo uprzejma i uniwersalna forma. W restauracji możesz użyć jej z menu, wodą, rachunkiem albo dodatkowym talerzem.`, practice: [`Poproś o menu.`,`Zapytaj kelnera, co poleca.`,`Zamów zupę i kurczaka.`,`Powiedz, że nie chcesz deseru.`,`Przećwicz wymowę „Ne tavsiye edersiniz?”.`]},{day: 12, title: `Dieta i alergie`, title_native: `Diyet ve alerjiler`, focus: `Dziś nauczysz się mówić o ograniczeniach jedzeniowych. To ważne w restauracji, piekarni i przy ulicznym jedzeniu.`, vocab: [{tr: `alerji`, pl: `alergia`, ipa: `a-ler-żi`},{tr: `fındık`, pl: `orzech laskowy`, ipa: `fyn-dyk`},{tr: `yer fıstığı`, pl: `orzeszek ziemny`, ipa: `jer fys-ty-y`},{tr: `süt`, pl: `mleko`, ipa: `syt`},{tr: `glüten`, pl: `gluten`, ipa: `gly-ten`},{tr: `vejetaryen`, pl: `wegetariański`, ipa: `we-że-tar-jen`},{tr: `acı`, pl: `ostre`, ipa: `a-dży`},{tr: `tuz`, pl: `sól`, ipa: `tuz`},{tr: `şeker`, pl: `cukier`, ipa: `sze-ker`},{tr: `içinde`, pl: `w środku / zawiera`, ipa: `i-czin-de`}], phrases: [{tr: `Alerjim var.`, pl: `Mam alergię.`, ipa: `a-ler-żim war`},{tr: `Fındık alerjim var.`, pl: `Mam alergię na orzechy laskowe.`, ipa: `fyn-dyk a-ler-żim war`},{tr: `İçinde süt var mı?`, pl: `Czy to zawiera mleko?`, ipa: `i-czin-de syt war my`},{tr: `Acı değil lütfen.`, pl: `Nieostre proszę.`, ipa: `a-dży de-jil lyt-fen`},{tr: `Vejetaryen yemek var mı?`, pl: `Czy jest danie wegetariańskie?`, ipa: `we-że-tar-jen je-mek war my`},{tr: `Glütensiz var mı?`, pl: `Czy jest bezglutenowe?`, ipa: `gly-ten-siz war my`}], grammar: `„İçinde ... var mı?” znaczy „czy w środku jest...?” albo „czy to zawiera...?”. To bardzo użyteczna konstrukcja przy alergiach. Pamiętaj, że w Turcji dania mogą zawierać orzechy, nabiał lub przyprawy, więc warto pytać jasno.`, practice: [`Powiedz, że masz alergię.`,`Zapytaj, czy danie zawiera mleko.`,`Poproś o nieostre jedzenie.`,`Zapytaj o danie wegetariańskie.`,`Napisz zdanie z własną alergią lub ograniczeniem.`]},{day: 13, title: `Pieniądze i płatność`, title_native: `Para ve ödeme`, focus: `Nauczysz się płacić gotówką lub kartą. Przyda się to w restauracji, sklepie i przy zakupie biletu.`, vocab: [{tr: `para`, pl: `pieniądze`, ipa: `pa-ra`},{tr: `lira`, pl: `lira`, ipa: `li-ra`},{tr: `nakit`, pl: `gotówka`, ipa: `na-kit`},{tr: `kart`, pl: `karta`, ipa: `kart`},{tr: `ödeme`, pl: `płatność`, ipa: `y-de-me`},{tr: `fiş`, pl: `paragon`, ipa: `fisz`},{tr: `hesap`, pl: `rachunek`, ipa: `he-sap`},{tr: `pahalı`, pl: `drogi`, ipa: `pa-ha-ly`},{tr: `ucuz`, pl: `tani`, ipa: `u-dżuz`},{tr: `bozuk para`, pl: `drobne`, ipa: `bo-zuk pa-ra`}], phrases: [{tr: `Kartla ödeyebilir miyim?`, pl: `Czy mogę zapłacić kartą?`, ipa: `kart-la y-de-je-bi-lir mi-jim`},{tr: `Nakit ödeyeceğim.`, pl: `Zapłacę gotówką.`, ipa: `na-kit y-de-je-dże-im`},{tr: `Hesap lütfen.`, pl: `Rachunek poproszę.`, ipa: `he-sap lyt-fen`},{tr: `Fiş alabilir miyim?`, pl: `Czy mogę dostać paragon?`, ipa: `fisz a-la-bi-lir mi-jim`},{tr: `Çok pahalı.`, pl: `Bardzo drogie.`, ipa: `czok pa-ha-ly`},{tr: `Daha ucuz var mı?`, pl: `Czy jest coś tańszego?`, ipa: `da-ha u-dżuz war my`}], grammar: `„-la / -le” oznacza często „za pomocą” lub „z”, jak w „kartla” — kartą. „Ödeyebilir miyim?” to grzeczne „czy mogę zapłacić?”. W tureckich sklepach pytanie o kartę jest bardzo naturalne, ale w małych miejscach gotówka nadal bywa przydatna.`, practice: [`Zapytaj, czy możesz zapłacić kartą.`,`Powiedz, że zapłacisz gotówką.`,`Poproś o paragon.`,`Powiedz, że coś jest bardzo drogie.`,`Zapytaj o tańszą opcję.`]},{day: 14, title: `Zakupy na bazarze`, title_native: `Pazarda alışveriş`, focus: `Dziś ćwiczysz słownictwo z bazaru, gdzie sprzedaje się przyprawy, owoce i pamiątki. To szczególnie przydatne na targach w Stambule i Izmirze.`, vocab: [{tr: `pazar`, pl: `bazar / targ`, ipa: `pa-zar`},{tr: `alışveriş`, pl: `zakupy`, ipa: `a-lysz-we-risz`},{tr: `meyve`, pl: `owoce`, ipa: `mej-we`},{tr: `sebze`, pl: `warzywa`, ipa: `seb-ze`},{tr: `baharat`, pl: `przyprawa`, ipa: `ba-ha-rat`},{tr: `hediye`, pl: `prezent`, ipa: `he-di-je`},{tr: `çanta`, pl: `torba`, ipa: `czan-ta`},{tr: `kilo`, pl: `kilogram`, ipa: `ki-lo`},{tr: `yarım`, pl: `pół`, ipa: `ja-rym`},{tr: `taze`, pl: `świeży`, ipa: `ta-ze`}], phrases: [{tr: `Yarım kilo lütfen.`, pl: `Pół kilo poproszę.`, ipa: `ja-rym ki-lo lyt-fen`},{tr: `Bu taze mi?`, pl: `Czy to jest świeże?`, ipa: `bu ta-ze mi`},{tr: `Bir çanta alabilir miyim?`, pl: `Czy mogę dostać torbę?`, ipa: `bir czan-ta a-la-bi-lir mi-jim`},{tr: `Hediye için.`, pl: `Na prezent.`, ipa: `he-di-je i-czin`},{tr: `Ne kadar?`, pl: `Ile kosztuje?`, ipa: `ne ka-dar`},{tr: `Biraz indirim var mı?`, pl: `Czy jest mała zniżka?`, ipa: `bi-raz in-di-rim war my`}], grammar: `„Ne kadar?” to bardzo częste pytanie o cenę lub ilość: „ile?”. Na bazarze możesz też usłyszeć „Buyurun”, czyli „proszę / zapraszam”. Targowanie bywa możliwe na bazarach i przy pamiątkach, ale nie w supermarketach.`, practice: [`Poproś pół kilo owoców.`,`Zapytaj, czy produkt jest świeży.`,`Zapytaj o cenę.`,`Poproś o małą zniżkę.`,`Powiedz, że coś jest na prezent.`]},{day: 15, title: `Ubrania i rozmiary`, title_native: `Kıyafetler ve bedenler`, focus: `Nauczysz się kupować ubrania i pytać o rozmiar. Przyda się w centrum handlowym w Ankarze albo w małym sklepie w Bodrum.`, vocab: [{tr: `kıyafet`, pl: `ubranie`, ipa: `ky-ja-fet`},{tr: `gömlek`, pl: `koszula`, ipa: `gym-lek`},{tr: `pantolon`, pl: `spodnie`, ipa: `pan-to-lon`},{tr: `elbise`, pl: `sukienka`, ipa: `el-bi-se`},{tr: `ayakkabı`, pl: `buty`, ipa: `a-jak-ka-by`},{tr: `beden`, pl: `rozmiar`, ipa: `be-den`},{tr: `renk`, pl: `kolor`, ipa: `renk`},{tr: `mavi`, pl: `niebieski`, ipa: `ma-wi`},{tr: `siyah`, pl: `czarny`, ipa: `si-jah`},{tr: `beyaz`, pl: `biały`, ipa: `be-jaz`}], phrases: [{tr: `Bu beden var mı?`, pl: `Czy jest ten rozmiar?`, ipa: `bu be-den war my`},{tr: `Daha büyük var mı?`, pl: `Czy jest większy?`, ipa: `da-ha by-jyk war my`},{tr: `Daha küçük var mı?`, pl: `Czy jest mniejszy?`, ipa: `da-ha ky-czyk war my`},{tr: `Deneyebilir miyim?`, pl: `Czy mogę przymierzyć?`, ipa: `de-ne-je-bi-lir mi-jim`},{tr: `Siyah istiyorum.`, pl: `Chcę czarne.`, ipa: `si-jah is-ti-jo-rum`},{tr: `Bu bana uygun.`, pl: `To mi pasuje.`, ipa: `bu ba-na uj-gun`}], grammar: `„Daha” oznacza „bardziej / więcej” i pomaga tworzyć porównania: „daha büyük” to „większy”, „daha küçük” to „mniejszy”. „Deneyebilir miyim?” jest przydatne w sklepach odzieżowych i znaczy „czy mogę spróbować/przymierzyć?”.`, practice: [`Zapytaj o większy rozmiar.`,`Zapytaj o mniejszy rozmiar.`,`Poproś o czarny kolor.`,`Powiedz, że chcesz przymierzyć.`,`Powiedz, że coś ci pasuje.`]},{day: 16, title: `Kierunki w mieście`, title_native: `Şehirde yönler`, focus: `Dziś nauczysz się pytać o drogę i rozumieć podstawowe wskazówki. Przyda się podczas spaceru po Stambule, Izmirze lub Antalyi.`, vocab: [{tr: `sağ`, pl: `prawo`, ipa: `sa`},{tr: `sol`, pl: `lewo`, ipa: `sol`},{tr: `düz`, pl: `prosto`, ipa: `dyz`},{tr: `burada`, pl: `tutaj`, ipa: `bu-ra-da`},{tr: `orada`, pl: `tam`, ipa: `o-ra-da`},{tr: `karşıda`, pl: `naprzeciwko`, ipa: `kar-szy-da`},{tr: `yakın`, pl: `blisko`, ipa: `ja-kyn`},{tr: `uzak`, pl: `daleko`, ipa: `u-zak`},{tr: `köşe`, pl: `róg`, ipa: `ky-sze`},{tr: `sokak`, pl: `ulica`, ipa: `so-kak`}], phrases: [{tr: `Sağa dönün.`, pl: `Proszę skręcić w prawo.`, ipa: `sa-a dy-nyn`},{tr: `Sola dönün.`, pl: `Proszę skręcić w lewo.`, ipa: `so-la dy-nyn`},{tr: `Düz gidin.`, pl: `Proszę iść prosto.`, ipa: `dyz gi-din`},{tr: `Yakın mı?`, pl: `Czy to blisko?`, ipa: `ja-kyn my`},{tr: `Uzak mı?`, pl: `Czy to daleko?`, ipa: `u-zak my`},{tr: `Bu sokak nerede?`, pl: `Gdzie jest ta ulica?`, ipa: `bu so-kak ne-re-de`}], grammar: `W tureckim forma grzecznego polecenia często kończy się na „-in” lub „-ün”, jak „gidin” i „dönün”. Gdy pytasz o drogę, możesz używać prostych zdań bez pełnej gramatyki. „Düz gidin” to jedno z najważniejszych zdań do rozumienia w mieście.`, practice: [`Powiedz „proszę iść prosto”.`,`Powiedz „proszę skręcić w lewo”.`,`Zapytaj, czy miejsce jest blisko.`,`Zapytaj, gdzie jest ta ulica.`,`Narysuj prostą mapkę i opisz trasę trzema tureckimi zwrotami.`]},{day: 17, title: `Transport publiczny`, title_native: `Toplu taşıma`, focus: `Nauczysz się mówić o metrze, autobusie, tramwaju i przystankach. To bardzo praktyczne w Stambule, gdzie transport publiczny jest częścią codziennego zwiedzania.`, vocab: [{tr: `metro`, pl: `metro`, ipa: `met-ro`},{tr: `otobüs`, pl: `autobus`, ipa: `o-to-bys`},{tr: `tramvay`, pl: `tramwaj`, ipa: `tram-waj`},{tr: `durak`, pl: `przystanek`, ipa: `du-rak`},{tr: `istasyon`, pl: `stacja`, ipa: `is-ta-sjon`},{tr: `bilet`, pl: `bilet`, ipa: `bi-let`},{tr: `kart`, pl: `karta`, ipa: `kart`},{tr: `hat`, pl: `linia`, ipa: `hat`},{tr: `son durak`, pl: `ostatni przystanek`, ipa: `son du-rak`},{tr: `aktarma`, pl: `przesiadka`, ipa: `ak-tar-ma`}], phrases: [{tr: `Metro nerede?`, pl: `Gdzie jest metro?`, ipa: `met-ro ne-re-de`},{tr: `Bu otobüs nereye gidiyor?`, pl: `Dokąd jedzie ten autobus?`, ipa: `bu o-to-bys ne-re-je gi-di-jor`},{tr: `Bir bilet lütfen.`, pl: `Jeden bilet poproszę.`, ipa: `bir bi-let lyt-fen`},{tr: `Hangi hat?`, pl: `Która linia?`, ipa: `han-gi hat`},{tr: `Aktarma var mı?`, pl: `Czy jest przesiadka?`, ipa: `ak-tar-ma war my`},{tr: `Son durak burası mı?`, pl: `Czy to ostatni przystanek?`, ipa: `son du-rak bu-ra-sy my`}], grammar: `„Nereye?” oznacza „dokąd?”, a „nerede?” oznacza „gdzie?”. Różnica jest ważna: „Metro nerede?” pytasz o lokalizację metra, a „Nereye gidiyor?” pytasz, dokąd coś jedzie. „Gidiyor” znaczy „idzie/jedzie”.`, practice: [`Zapytaj, gdzie jest metro.`,`Zapytaj, dokąd jedzie autobus.`,`Poproś o jeden bilet.`,`Zapytaj, czy jest przesiadka.`,`Zapytaj, która to linia.`]},{day: 18, title: `Taksówka i przejazd`, title_native: `Taksi ve yolculuk`, focus: `Dziś ćwiczysz rozmowę z taksówkarzem. Nauczysz się podawać adres, pytać o cenę i prosić o zatrzymanie.`, vocab: [{tr: `taksi`, pl: `taksówka`, ipa: `tak-si`},{tr: `adres`, pl: `adres`, ipa: `ad-res`},{tr: `şoför`, pl: `kierowca`, ipa: `szo-fyr`},{tr: `buraya`, pl: `tutaj / do tego miejsca`, ipa: `bu-ra-ja`},{tr: `otelime`, pl: `do mojego hotelu`, ipa: `o-te-li-me`},{tr: `hızlı`, pl: `szybki`, ipa: `hyz-ly`},{tr: `yavaş`, pl: `wolny / powoli`, ipa: `ja-wasz`},{tr: `dur`, pl: `stop`, ipa: `dur`},{tr: `sağda`, pl: `po prawej`, ipa: `sa-da`},{tr: `solda`, pl: `po lewej`, ipa: `sol-da`}], phrases: [{tr: `Bu adrese lütfen.`, pl: `Pod ten adres proszę.`, ipa: `bu ad-re-se lyt-fen`},{tr: `Otelime gidelim.`, pl: `Jedźmy do mojego hotelu.`, ipa: `o-te-li-me gi-de-lim`},{tr: `Ne kadar tutar?`, pl: `Ile to będzie kosztować?`, ipa: `ne ka-dar tu-tar`},{tr: `Burada durun lütfen.`, pl: `Proszę zatrzymać się tutaj.`, ipa: `bu-ra-da du-run lyt-fen`},{tr: `Sağda lütfen.`, pl: `Po prawej proszę.`, ipa: `sa-da lyt-fen`},{tr: `Yavaş lütfen.`, pl: `Wolniej proszę.`, ipa: `ja-wasz lyt-fen`}], grammar: `„-e / -a” często oznacza kierunek „do”, jak w „adrese” — pod adres, „otelime” — do mojego hotelu. „Gidelim” znaczy „chodźmy / jedźmy”. To naturalny sposób mówienia, gdy prosisz kierowcę o ruszenie w konkretne miejsce.`, practice: [`Powiedz kierowcy „pod ten adres proszę”.`,`Zapytaj, ile będzie kosztować przejazd.`,`Poproś o zatrzymanie się tutaj.`,`Powiedz „po prawej proszę”.`,`Odegraj krótką rozmowę z taksówkarzem od wejścia do zapłaty.`]},{day: 19, title: `Czas i godziny`, title_native: `Saat ve zaman`, focus: `Nauczysz się pytać o godzinę i umawiać się na konkretny czas. Przyda się przy wycieczkach, rezerwacjach i odjazdach.`, vocab: [{tr: `saat`, pl: `godzina / zegarek`, ipa: `sa-at`},{tr: `zaman`, pl: `czas`, ipa: `za-man`},{tr: `bugün`, pl: `dzisiaj`, ipa: `bu-gyn`},{tr: `yarın`, pl: `jutro`, ipa: `ja-ryn`},{tr: `dün`, pl: `wczoraj`, ipa: `dyn`},{tr: `sabah`, pl: `rano`, ipa: `sa-bah`},{tr: `öğle`, pl: `południe`, ipa: `y-le`},{tr: `akşam`, pl: `wieczór`, ipa: `ak-szam`},{tr: `gece`, pl: `noc`, ipa: `ge-dże`},{tr: `erken`, pl: `wcześnie`, ipa: `er-ken`}], phrases: [{tr: `Saat kaç?`, pl: `Która godzina?`, ipa: `sa-at kacz`},{tr: `Saat üç.`, pl: `Jest trzecia.`, ipa: `sa-at ycz`},{tr: `Ne zaman açılıyor?`, pl: `Kiedy się otwiera?`, ipa: `ne za-man a-czy-ly-jor`},{tr: `Ne zaman kapanıyor?`, pl: `Kiedy się zamyka?`, ipa: `ne za-man ka-pa-ny-jor`},{tr: `Yarın sabah.`, pl: `Jutro rano.`, ipa: `ja-ryn sa-bah`},{tr: `Akşam görüşürüz.`, pl: `Widzimy się wieczorem.`, ipa: `ak-szam gy-ry-szy-ryz`}], grammar: `„Saat kaç?” dosłownie znaczy „godzina ile?”. W tureckim godziny można mówić prosto: „Saat üç” — jest trzecia. Do podróży wystarczy znać liczby i pory dnia, nawet jeśli dokładne formy godzin są bardziej złożone.`, practice: [`Zapytaj, która godzina.`,`Powiedz „jest trzecia”.`,`Zapytaj, kiedy miejsce się otwiera.`,`Powiedz „jutro rano”.`,`Umów się z kimś na wieczór.`]},{day: 20, title: `Rezerwacje i plany`, title_native: `Rezervasyonlar ve planlar`, focus: `Dziś nauczysz się robić proste rezerwacje i mówić o planach. To przyda się przy restauracji, wycieczce łodzią lub wizycie w hammamie.`, vocab: [{tr: `rezervasyon`, pl: `rezerwacja`, ipa: `re-zer-wa-sjon`},{tr: `plan`, pl: `plan`, ipa: `plan`},{tr: `bugün`, pl: `dzisiaj`, ipa: `bu-gyn`},{tr: `yarın`, pl: `jutro`, ipa: `ja-ryn`},{tr: `kişi`, pl: `osoba`, ipa: `ki-szi`},{tr: `masa`, pl: `stolik`, ipa: `ma-sa`},{tr: `tur`, pl: `wycieczka`, ipa: `tur`},{tr: `müsait`, pl: `dostępny / wolny`, ipa: `my-sa-it`},{tr: `dolu`, pl: `pełny / zajęty`, ipa: `do-lu`},{tr: `iptal`, pl: `anulowanie`, ipa: `ip-tal`}], phrases: [{tr: `İki kişi için rezervasyon.`, pl: `Rezerwacja dla dwóch osób.`, ipa: `i-ki ki-szi i-czin re-zer-wa-sjon`},{tr: `Yarın için masa var mı?`, pl: `Czy jest stolik na jutro?`, ipa: `ja-ryn i-czin ma-sa war my`},{tr: `Bugün müsait misiniz?`, pl: `Czy mają państwo dziś wolne miejsca?`, ipa: `bu-gyn my-sa-it mi-si-niz`},{tr: `Tur saat kaçta?`, pl: `O której jest wycieczka?`, ipa: `tur sa-at kacz-ta`},{tr: `Rezervasyonu iptal etmek istiyorum.`, pl: `Chcę anulować rezerwację.`, ipa: `re-zer-wa-sjo-nu ip-tal et-mek is-ti-jo-rum`},{tr: `Dolu mu?`, pl: `Czy jest pełne/zajęte?`, ipa: `do-lu mu`}], grammar: `„İçin” znaczy „dla” albo „na”, jak „iki kişi için” — dla dwóch osób, „yarın için” — na jutro. „Müsait misiniz?” to uprzejme pytanie o dostępność. Można go użyć w hotelu, restauracji lub salonie usługowym.`, practice: [`Zrób rezerwację dla dwóch osób.`,`Zapytaj o stolik na jutro.`,`Zapytaj, o której jest wycieczka.`,`Powiedz, że chcesz anulować rezerwację.`,`Ułóż rozmowę telefoniczną z restauracją.`]},{day: 21, title: `Zwiedzanie i atrakcje`, title_native: `Gezilecek yerler ve turistik yerler`, focus: `Nauczysz się mówić o muzeach, zabytkach i biletach. To przyda się przy zwiedzaniu Hagii Sophii, Efezu lub muzeów w Ankarze.`, vocab: [{tr: `müze`, pl: `muzeum`, ipa: `my-ze`},{tr: `cami`, pl: `meczet`, ipa: `dża-mi`},{tr: `saray`, pl: `pałac`, ipa: `sa-raj`},{tr: `kale`, pl: `zamek / twierdza`, ipa: `ka-le`},{tr: `bilet gişesi`, pl: `kasa biletowa`, ipa: `bi-let gi-sze-si`},{tr: `giriş ücreti`, pl: `opłata za wejście`, ipa: `gi-risz y-dżre-ti`},{tr: `rehber`, pl: `przewodnik`, ipa: `reh-ber`},{tr: `turist`, pl: `turysta`, ipa: `tu-rist`},{tr: `fotoğraf`, pl: `zdjęcie`, ipa: `fo-to-raf`},{tr: `yasak`, pl: `zakazany`, ipa: `ja-sak`}], phrases: [{tr: `Müze nerede?`, pl: `Gdzie jest muzeum?`, ipa: `my-ze ne-re-de`},{tr: `Giriş ücreti ne kadar?`, pl: `Ile kosztuje wejście?`, ipa: `gi-risz y-dżre-ti ne ka-dar`},{tr: `Fotoğraf çekebilir miyim?`, pl: `Czy mogę zrobić zdjęcie?`, ipa: `fo-to-raf cze-ke-bi-lir mi-jim`},{tr: `Rehber var mı?`, pl: `Czy jest przewodnik?`, ipa: `reh-ber war my`},{tr: `Bilet gişesi nerede?`, pl: `Gdzie jest kasa biletowa?`, ipa: `bi-let gi-sze-si ne-re-de`},{tr: `Fotoğraf yasak mı?`, pl: `Czy zdjęcia są zakazane?`, ipa: `fo-to-raf ja-sak my`}], grammar: `„Çekmek” z „fotoğraf” oznacza „robić zdjęcie”. Forma „çekebilir miyim?” to „czy mogę zrobić?”. W miejscach religijnych i muzeach warto pytać o zdjęcia, ubiór i zasady, nawet jeśli inni turyści robią coś inaczej.`, practice: [`Zapytaj, gdzie jest muzeum.`,`Zapytaj o cenę wejścia.`,`Zapytaj, czy możesz zrobić zdjęcie.`,`Zapytaj, czy jest przewodnik.`,`Powiedz, że zdjęcia są zakazane.`]},{day: 22, title: `Zdrowie i apteka`, title_native: `Sağlık ve eczane`, focus: `Dziś poznasz słowa potrzebne w aptece i przy drobnych problemach zdrowotnych. To ważne, gdy boli cię głowa, brzuch albo potrzebujesz lekarstwa.`, vocab: [{tr: `eczane`, pl: `apteka`, ipa: `ed-ża-ne`},{tr: `ilaç`, pl: `lekarstwo`, ipa: `i-lacz`},{tr: `doktor`, pl: `lekarz`, ipa: `dok-tor`},{tr: `hastane`, pl: `szpital`, ipa: `has-ta-ne`},{tr: `baş`, pl: `głowa`, ipa: `basz`},{tr: `karın`, pl: `brzuch`, ipa: `ka-ryn`},{tr: `ağrı`, pl: `ból`, ipa: `a-ry`},{tr: `ateş`, pl: `gorączka`, ipa: `a-tesz`},{tr: `öksürük`, pl: `kaszel`, ipa: `yk-sy-ryk`},{tr: `yardım`, pl: `pomoc`, ipa: `jar-dym`}], phrases: [{tr: `Eczane nerede?`, pl: `Gdzie jest apteka?`, ipa: `ed-ża-ne ne-re-de`},{tr: `Başım ağrıyor.`, pl: `Boli mnie głowa.`, ipa: `ba-szym a-ry-jor`},{tr: `Karnım ağrıyor.`, pl: `Boli mnie brzuch.`, ipa: `kar-nym a-ry-jor`},{tr: `İlaç alabilir miyim?`, pl: `Czy mogę dostać lekarstwo?`, ipa: `i-lacz a-la-bi-lir mi-jim`},{tr: `Doktora ihtiyacım var.`, pl: `Potrzebuję lekarza.`, ipa: `dok-to-ra ih-ti-ja-dżym war`},{tr: `Yardım lütfen.`, pl: `Pomocy proszę.`, ipa: `jar-dym lyt-fen`}], grammar: `Końcówka „-ım / -im” przy częściach ciała często oznacza „mój”: „başım” — moja głowa, „karnım” — mój brzuch. „Ağrıyor” oznacza „boli”. W nagłej sytuacji najprostsze „Yardım lütfen” jest zrozumiałe i skuteczne.`, practice: [`Zapytaj, gdzie jest apteka.`,`Powiedz, że boli cię głowa.`,`Powiedz, że boli cię brzuch.`,`Powiedz, że potrzebujesz lekarza.`,`Poproś o pomoc.`]},{day: 23, title: `Nagłe sytuacje`, title_native: `Acil durumlar`, focus: `Nauczysz się podstawowych zwrotów na wypadek zgubienia rzeczy, problemu lub potrzeby pomocy. To słownictwo jest ważne w każdym mieście.`, vocab: [{tr: `acil`, pl: `pilny / nagły`, ipa: `a-dżil`},{tr: `polis`, pl: `policja`, ipa: `po-lis`},{tr: `yardım`, pl: `pomoc`, ipa: `jar-dym`},{tr: `kayboldum`, pl: `zgubiłem się`, ipa: `kaj-bol-dum`},{tr: `çantam`, pl: `moja torba`, ipa: `czan-tam`},{tr: `telefonum`, pl: `mój telefon`, ipa: `te-le-fo-num`},{tr: `pasaportum`, pl: `mój paszport`, ipa: `pa-sa-por-tum`},{tr: `çalındı`, pl: `został skradziony`, ipa: `cza-lyn-dy`},{tr: `kayıp`, pl: `zgubiony`, ipa: `ka-jyp`},{tr: `tehlike`, pl: `niebezpieczeństwo`, ipa: `teh-li-ke`}], phrases: [{tr: `Yardım edin lütfen.`, pl: `Proszę mi pomóc.`, ipa: `jar-dym e-din lyt-fen`},{tr: `Kayboldum.`, pl: `Zgubiłem/Zgubiłam się.`, ipa: `kaj-bol-dum`},{tr: `Telefonum kayıp.`, pl: `Mój telefon zaginął.`, ipa: `te-le-fo-num ka-jyp`},{tr: `Pasaportum çalındı.`, pl: `Mój paszport został skradziony.`, ipa: `pa-sa-por-tum cza-lyn-dy`},{tr: `Polis nerede?`, pl: `Gdzie jest policja?`, ipa: `po-lis ne-re-de`},{tr: `Acil durum.`, pl: `Nagła sytuacja.`, ipa: `a-dżil du-rum`}], grammar: `„-um / -ım” ponownie wskazuje posiadanie: „telefonum”, „pasaportum”, „çantam”. „Çalındı” oznacza „zostało skradzione”, a „kayıp” to „zgubiony / zaginiony”. W stresie używaj krótkich zdań i pokazuj dokumenty lub lokalizację na telefonie.`, practice: [`Powiedz, że się zgubiłeś.`,`Powiedz, że twój telefon zaginął.`,`Powiedz, że paszport został skradziony.`,`Zapytaj, gdzie jest policja.`,`Przećwicz zdanie „Yardım edin lütfen” głośno i wyraźnie.`]},{day: 24, title: `Pogoda i ubranie na dzień`, title_native: `Hava durumu ve günlük kıyafet`, focus: `Nauczysz się mówić o pogodzie, co przyda się przy planowaniu plaży, spaceru lub wycieczki. Turcja ma różne klimaty, więc warto znać te słowa.`, vocab: [{tr: `hava`, pl: `pogoda / powietrze`, ipa: `ha-wa`},{tr: `sıcak`, pl: `gorąco`, ipa: `sy-dżak`},{tr: `soğuk`, pl: `zimno`, ipa: `so-uk`},{tr: `güneşli`, pl: `słonecznie`, ipa: `gy-nesz-li`},{tr: `yağmurlu`, pl: `deszczowo`, ipa: `ja-mur-lu`},{tr: `rüzgarlı`, pl: `wietrznie`, ipa: `ryz-gar-ly`},{tr: `bulutlu`, pl: `pochmurno`, ipa: `bu-lut-lu`},{tr: `şemsiye`, pl: `parasol`, ipa: `szem-si-je`},{tr: `ceket`, pl: `kurtka`, ipa: `dże-ket`},{tr: `deniz`, pl: `morze`, ipa: `de-niz`}], phrases: [{tr: `Hava nasıl?`, pl: `Jaka jest pogoda?`, ipa: `ha-wa na-syl`},{tr: `Bugün çok sıcak.`, pl: `Dziś jest bardzo gorąco.`, ipa: `bu-gyn czok sy-dżak`},{tr: `Yağmur var mı?`, pl: `Czy pada deszcz?`, ipa: `ja-mur war my`},{tr: `Deniz güzel mi?`, pl: `Czy morze jest ładne/spokojne?`, ipa: `de-niz gy-zel mi`},{tr: `Şemsiye lazım mı?`, pl: `Czy potrzebny jest parasol?`, ipa: `szem-si-je la-zym my`},{tr: `Ceket almalıyım.`, pl: `Powinienem wziąć kurtkę.`, ipa: `dże-ket al-ma-ly-jym`}], grammar: `„Lazım” oznacza „potrzebny”, jak w „Şemsiye lazım mı?” — czy parasol jest potrzebny? „Bugün” to „dzisiaj”, więc łatwo budować zdania o planach. W rozmowie pogodowej krótkie przymiotniki są całkowicie wystarczające.`, practice: [`Zapytaj, jaka jest pogoda.`,`Powiedz, że dziś jest gorąco.`,`Zapytaj, czy pada deszcz.`,`Zapytaj, czy potrzebny jest parasol.`,`Powiedz, że powinieneś wziąć kurtkę.`]},{day: 25, title: `Rozmowy towarzyskie`, title_native: `Sosyal konuşmalar`, focus: `Dziś nauczysz się prowadzić małą rozmowę z lokalną osobą. Przyda się w kawiarni, sklepie rodzinnym albo podczas wycieczki.`, vocab: [{tr: `nasılsınız`, pl: `jak się pan/pani ma`, ipa: `na-syl-sy-nyz`},{tr: `iyiyim`, pl: `mam się dobrze`, ipa: `i-ji-jim`},{tr: `güzel`, pl: `piękny / dobry`, ipa: `gy-zel`},{tr: `şehir`, pl: `miasto`, ipa: `sze-hir`},{tr: `gezmek`, pl: `zwiedzać / spacerować`, ipa: `gez-mek`},{tr: `tatil`, pl: `wakacje`, ipa: `ta-til`},{tr: `iş`, pl: `praca`, ipa: `isz`},{tr: `aile`, pl: `rodzina`, ipa: `a-i-le`},{tr: `arkadaş`, pl: `znajomy`, ipa: `ar-ka-dasz`},{tr: `hoş`, pl: `miły`, ipa: `hosz`}], phrases: [{tr: `Nasılsınız?`, pl: `Jak się pan/pani ma?`, ipa: `na-syl-sy-nyz`},{tr: `İyiyim, teşekkürler.`, pl: `Mam się dobrze, dziękuję.`, ipa: `i-ji-jim te-szek-kyr-ler`},{tr: `Şehir çok güzel.`, pl: `Miasto jest bardzo piękne.`, ipa: `sze-hir czok gy-zel`},{tr: `Tatil için geldim.`, pl: `Przyjechałem/Przyjechałam na wakacje.`, ipa: `ta-til i-czin gel-dim`},{tr: `Polonya’dan geldim.`, pl: `Przyjechałem/Przyjechałam z Polski.`, ipa: `po-lon-ja-dan gel-dim`},{tr: `Sizinle tanışmak güzel.`, pl: `Miło pana/panią poznać.`, ipa: `si-zin-le ta-nysz-mak gy-zel`}], grammar: `„-dan / -den” oznacza „z, od”, jak w „Polonya’dan” — z Polski. „Geldim” znaczy „przyjechałem/przyszedłem”. Zwrot „... için geldim” pozwala powiedzieć, po co przyjechałeś: „tatil için geldim” — przyjechałem na wakacje.`, practice: [`Zapytaj kogoś, jak się ma.`,`Odpowiedz, że masz się dobrze.`,`Powiedz, że miasto jest piękne.`,`Powiedz, że przyjechałeś z Polski.`,`Powiedz, że przyjechałeś na wakacje.`]},{day: 26, title: `Zaproszenia i propozycje`, title_native: `Davetler ve öneriler`, focus: `Nauczysz się proponować spotkanie, kawę lub wspólny spacer. To przydatne, gdy poznasz kogoś w hostelu, na kursie gotowania lub wycieczce.`, vocab: [{tr: `davet`, pl: `zaproszenie`, ipa: `da-wet`},{tr: `kahve`, pl: `kawa`, ipa: `kah-we`},{tr: `yemek`, pl: `jedzenie / posiłek`, ipa: `je-mek`},{tr: `beraber`, pl: `razem`, ipa: `be-ra-ber`},{tr: `gidelim`, pl: `chodźmy / jedźmy`, ipa: `gi-de-lim`},{tr: `ister misiniz`, pl: `czy pan/pani chce`, ipa: `is-ter mi-si-niz`},{tr: `müsait`, pl: `dostępny`, ipa: `my-sa-it`},{tr: `sonra`, pl: `później`, ipa: `son-ra`},{tr: `akşam`, pl: `wieczór`, ipa: `ak-szam`},{tr: `buluşmak`, pl: `spotkać się`, ipa: `bu-lusz-mak`}], phrases: [{tr: `Kahve içelim mi?`, pl: `Napijemy się kawy?`, ipa: `kah-we i-cze-lim mi`},{tr: `Beraber gidelim mi?`, pl: `Pójdziemy razem?`, ipa: `be-ra-ber gi-de-lim mi`},{tr: `Akşam müsait misiniz?`, pl: `Czy ma pan/pani czas wieczorem?`, ipa: `ak-szam my-sa-it mi-si-niz`},{tr: `Sonra buluşalım mı?`, pl: `Spotkamy się później?`, ipa: `son-ra bu-lu-sza-lym my`},{tr: `Yemek yiyelim mi?`, pl: `Zjemy coś?`, ipa: `je-mek ji-je-lim mi`},{tr: `Evet, olur.`, pl: `Tak, może być.`, ipa: `e-wet o-lur`}], grammar: `Końcówka „-elim / -alım” często tworzy propozycję „zróbmy coś”, jak „gidelim” — chodźmy, „buluşalım” — spotkajmy się. Dodanie „mi?” zamienia to w pytanie. To naturalny, przyjazny sposób proponowania planów.`, practice: [`Zaproponuj kawę.`,`Zapytaj, czy ktoś ma czas wieczorem.`,`Zaproponuj wspólny spacer lub wyjście.`,`Odpowiedz „Tak, może być”.`,`Ułóż trzy propozycje z użyciem „mi?”.`]},{day: 27, title: `Telefon i internet`, title_native: `Telefon ve internet`, focus: `Dziś nauczysz się pytać o kartę SIM, Wi-Fi, ładowarkę i zasięg. To bardzo praktyczne dla podróżnika korzystającego z map i rezerwacji online.`, vocab: [{tr: `telefon`, pl: `telefon`, ipa: `te-le-fon`},{tr: `internet`, pl: `internet`, ipa: `in-ter-net`},{tr: `Wi-Fi`, pl: `Wi-Fi`, ipa: `waj-faj`},{tr: `şarj`, pl: `ładowanie`, ipa: `szarż`},{tr: `şarj aleti`, pl: `ładowarka`, ipa: `szarż a-le-ti`},{tr: `SIM kart`, pl: `karta SIM`, ipa: `sim kart`},{tr: `hat`, pl: `linia / numer telefonu`, ipa: `hat`},{tr: `çekmiyor`, pl: `nie ma zasięgu`, ipa: `czek-mi-jor`},{tr: `şifre`, pl: `hasło`, ipa: `szyf-re`},{tr: `uygulama`, pl: `aplikacja`, ipa: `uj-gu-la-ma`}], phrases: [{tr: `Wi-Fi şifresi nedir?`, pl: `Jakie jest hasło do Wi-Fi?`, ipa: `waj-faj szyf-re-si ne-dir`},{tr: `Şarj aleti var mı?`, pl: `Czy jest ładowarka?`, ipa: `szarż a-le-ti war my`},{tr: `Telefonum çekmiyor.`, pl: `Mój telefon nie ma zasięgu.`, ipa: `te-le-fo-num czek-mi-jor`},{tr: `SIM kart almak istiyorum.`, pl: `Chcę kupić kartę SIM.`, ipa: `sim kart al-mak is-ti-jo-rum`},{tr: `Bu uygulama çalışmıyor.`, pl: `Ta aplikacja nie działa.`, ipa: `bu uj-gu-la-ma cza-lysz-my-jor`},{tr: `İnternet lazım.`, pl: `Potrzebuję internetu.`, ipa: `in-ter-net la-zym`}], grammar: `„Almak istiyorum” oznacza „chcę kupić / wziąć”. Czasownik w formie podstawowej plus „istiyorum” tworzy praktyczną konstrukcję: „gitmek istiyorum” — chcę iść, „almak istiyorum” — chcę kupić. „Lazım” jest prostsze i znaczy „potrzebne”.`, practice: [`Zapytaj o hasło do Wi-Fi.`,`Powiedz, że potrzebujesz internetu.`,`Powiedz, że twój telefon nie ma zasięgu.`,`Powiedz, że chcesz kupić kartę SIM.`,`Zapytaj, czy jest ładowarka.`]},{day: 28, title: `Pranie i codzienne sprawy`, title_native: `Çamaşır ve günlük işler`, focus: `Nauczysz się załatwiać codzienne rzeczy: pranie, sklep, wodę i podstawowe usługi. To przyda się przy dłuższym pobycie w Turcji.`, vocab: [{tr: `çamaşır`, pl: `pranie`, ipa: `cza-ma-szyr`},{tr: `çamaşırhane`, pl: `pralnia`, ipa: `cza-ma-szyr-ha-ne`},{tr: `market`, pl: `sklep spożywczy`, ipa: `mar-ket`},{tr: `su`, pl: `woda`, ipa: `su`},{tr: `sabun`, pl: `mydło`, ipa: `sa-bun`},{tr: `şampuan`, pl: `szampon`, ipa: `szam-pu-an`},{tr: `temiz`, pl: `czysty`, ipa: `te-miz`},{tr: `kirli`, pl: `brudny`, ipa: `kir-li`},{tr: `bugün`, pl: `dzisiaj`, ipa: `bu-gyn`},{tr: `yarın`, pl: `jutro`, ipa: `ja-ryn`}], phrases: [{tr: `Çamaşırhane nerede?`, pl: `Gdzie jest pralnia?`, ipa: `cza-ma-szyr-ha-ne ne-re-de`},{tr: `Çamaşır yıkamak istiyorum.`, pl: `Chcę zrobić pranie.`, ipa: `cza-ma-szyr jy-ka-mak is-ti-jo-rum`},{tr: `Market yakın mı?`, pl: `Czy sklep jest blisko?`, ipa: `mar-ket ja-kyn my`},{tr: `Su almak istiyorum.`, pl: `Chcę kupić wodę.`, ipa: `su al-mak is-ti-jo-rum`},{tr: `Bugün hazır mı?`, pl: `Czy będzie gotowe dziś?`, ipa: `bu-gyn ha-zyr my`},{tr: `Yarın alabilir miyim?`, pl: `Czy mogę odebrać jutro?`, ipa: `ja-ryn a-la-bi-lir mi-jim`}], grammar: `„Yıkamak” oznacza „myć / prać”, a „çamaşır yıkamak” to „robić pranie”. „Hazır” znaczy „gotowy”. W codziennych sprawach bardzo często przydają się pytania z „bugün” i „yarın”.`, practice: [`Zapytaj, gdzie jest pralnia.`,`Powiedz, że chcesz zrobić pranie.`,`Zapytaj, czy sklep jest blisko.`,`Powiedz, że chcesz kupić wodę.`,`Zapytaj, czy możesz odebrać coś jutro.`]},{day: 29, title: `Opinie i preferencje`, title_native: `Fikirler ve tercihler`, focus: `Nauczysz się mówić, co lubisz, czego nie lubisz i co wolisz. To pomaga w rozmowach z lokalnymi osobami i przy wyborze jedzenia lub planów.`, vocab: [{tr: `seviyorum`, pl: `lubię / kocham`, ipa: `se-wi-jo-rum`},{tr: `sevmiyorum`, pl: `nie lubię`, ipa: `sew-mi-jo-rum`},{tr: `tercih`, pl: `preferencja`, ipa: `ter-dżih`},{tr: `isterim`, pl: `chciałbym`, ipa: `is-te-rim`},{tr: `istemem`, pl: `nie chciałbym`, ipa: `is-te-mem`},{tr: `güzel`, pl: `ładny / dobry`, ipa: `gy-zel`},{tr: `lezzetli`, pl: `smaczny`, ipa: `lez-zet-li`},{tr: `çok`, pl: `bardzo`, ipa: `czok`},{tr: `az`, pl: `mało`, ipa: `az`},{tr: `en iyi`, pl: `najlepszy`, ipa: `en i-ji`}], phrases: [{tr: `Bunu seviyorum.`, pl: `Lubię to.`, ipa: `bu-nu se-wi-jo-rum`},{tr: `Bunu sevmiyorum.`, pl: `Nie lubię tego.`, ipa: `bu-nu sew-mi-jo-rum`},{tr: `Çok lezzetli.`, pl: `Bardzo smaczne.`, ipa: `czok lez-zet-li`},{tr: `Kahve tercih ederim.`, pl: `Wolę kawę.`, ipa: `kah-we ter-dżih e-de-rim`},{tr: `Az şeker isterim.`, pl: `Chciałbym mało cukru.`, ipa: `az sze-ker is-te-rim`},{tr: `En iyi yer nerede?`, pl: `Gdzie jest najlepsze miejsce?`, ipa: `en i-ji jer ne-re-de`}], grammar: `„Seviyorum” i „sevmiyorum” są bardzo przydatne w rozmowach o gustach. „Tercih ederim” oznacza „wolę” i brzmi uprzejmie. Możesz mówić prosto: „Kahve tercih ederim” — wolę kawę.`, practice: [`Powiedz, że lubisz to.`,`Powiedz, że nie lubisz tego.`,`Powiedz, że coś jest bardzo smaczne.`,`Powiedz, że wolisz kawę.`,`Zapytaj o najlepsze miejsce w okolicy.`]},{day: 30, title: `Łączenie wszystkiego w podróży`, title_native: `Seyahatte her şeyi birleştirme`, focus: `Ostatni dzień łączy najważniejsze zwroty z lotniska, hotelu, restauracji, zakupów i miasta. Celem jest swobodna, prosta komunikacja w prawdziwych sytuacjach.`, vocab: [{tr: `seyahat`, pl: `podróż`, ipa: `se-ja-hat`},{tr: `yardım`, pl: `pomoc`, ipa: `jar-dym`},{tr: `rezervasyon`, pl: `rezerwacja`, ipa: `re-zer-wa-sjon`},{tr: `adres`, pl: `adres`, ipa: `ad-res`},{tr: `bilet`, pl: `bilet`, ipa: `bi-let`},{tr: `hesap`, pl: `rachunek`, ipa: `he-sap`},{tr: `yakın`, pl: `blisko`, ipa: `ja-kyn`},{tr: `uzak`, pl: `daleko`, ipa: `u-zak`},{tr: `mümkün`, pl: `możliwe`, ipa: `mym-kyn`},{tr: `tekrar`, pl: `jeszcze raz / ponownie`, ipa: `tek-rar`}], phrases: [{tr: `Tekrar eder misiniz?`, pl: `Czy może pan/pani powtórzyć?`, ipa: `tek-rar e-der mi-si-niz`},{tr: `Yavaş konuşur musunuz?`, pl: `Czy może pan/pani mówić wolniej?`, ipa: `ja-wasz ko-nu-szur mu-su-nuz`},{tr: `Türkçe az biliyorum.`, pl: `Znam trochę turecki.`, ipa: `tyrk-cze az bi-li-jo-rum`},{tr: `Yardımınız için teşekkürler.`, pl: `Dziękuję za pomoc.`, ipa: `jar-dy-my-nyz i-czin te-szek-kyr-ler`},{tr: `Bu mümkün mü?`, pl: `Czy to możliwe?`, ipa: `bu mym-kyn my`},{tr: `Her şey tamam.`, pl: `Wszystko w porządku.`, ipa: `her szej ta-mam`}], grammar: `„Az biliyorum” znaczy „wiem/umiem trochę”, a „Türkçe az biliyorum” to świetne zdanie dla początkującego. „Yavaş konuşur musunuz?” jest bardzo uprzejme i praktyczne, gdy ktoś mówi zbyt szybko. W podróży proszenie o powtórzenie jest normalne i pomaga uniknąć nieporozumień.`, practice: [`Powiedz, że znasz trochę turecki.`,`Poproś, żeby ktoś mówił wolniej.`,`Poproś o powtórzenie.`,`Podziękuj za pomoc.`,`Zbuduj krótką rozmowę: pytasz o drogę, nie rozumiesz, prosisz o powtórzenie i dziękujesz.`]}];

var CONVERSATIONS_PL_TR = [{id: 1, title: `Zamawianie w kawiarni`, scene: `Jesteś w małej kawiarni w dzielnicy Kadıköy w Stambule. Chcesz zamówić herbatę, kawę i coś bez cukru.`, lines: [{who: `them`, tr: `Merhaba, buyurun.`, pl: `Dzień dobry, proszę.`},{who: `you`, tr: `Merhaba, bir çay lütfen.`, pl: `Dzień dobry, herbatę poproszę.`},{who: `them`, tr: `Başka bir şey ister misiniz?`, pl: `Czy chce pan/pani coś jeszcze?`},{who: `you`, tr: `Bir kahve de istiyorum.`, pl: `Chcę też jedną kawę.`},{who: `them`, tr: `Şekerli mi, şekersiz mi?`, pl: `Z cukrem czy bez cukru?`},{who: `you`, tr: `Şekersiz lütfen.`, pl: `Bez cukru proszę.`},{who: `them`, tr: `Süt ister misiniz?`, pl: `Czy chce pan/pani mleko?`},{who: `you`, tr: `Evet, sütlü olsun.`, pl: `Tak, niech będzie z mlekiem.`},{who: `them`, tr: `Tamam, hemen geliyor.`, pl: `Dobrze, zaraz będzie.`},{who: `you`, tr: `Teşekkürler.`, pl: `Dziękuję.`},{who: `them`, tr: `Bir şey değil.`, pl: `Nie ma za co.`}]},{id: 2, title: `Meldunek w hotelu`, scene: `Przyjeżdżasz wieczorem do hotelu w Izmirze. Masz rezerwację i chcesz zapytać o śniadanie oraz Wi-Fi.`, lines: [{who: `them`, tr: `İyi akşamlar, hoş geldiniz.`, pl: `Dobry wieczór, witamy.`},{who: `you`, tr: `İyi akşamlar, rezervasyonum var.`, pl: `Dobry wieczór, mam rezerwację.`},{who: `them`, tr: `Adınız ne?`, pl: `Jak ma pan/pani na imię?`},{who: `you`, tr: `Benim adım Anna Kowalska.`, pl: `Mam na imię Anna Kowalska.`},{who: `them`, tr: `Kimliğinizi alabilir miyim?`, pl: `Czy mogę prosić dokument?`},{who: `you`, tr: `Evet, kimliğim burada.`, pl: `Tak, mój dokument jest tutaj.`},{who: `them`, tr: `Kahvaltı saat yedide başlıyor.`, pl: `Śniadanie zaczyna się o siódmej.`},{who: `you`, tr: `Kahvaltı dahil mi?`, pl: `Czy śniadanie jest wliczone?`},{who: `them`, tr: `Evet, dahil.`, pl: `Tak, jest wliczone.`},{who: `you`, tr: `Wi-Fi şifresi nedir?`, pl: `Jakie jest hasło do Wi-Fi?`},{who: `them`, tr: `Şifre resepsiyonda yazıyor.`, pl: `Hasło jest napisane w recepcji.`},{who: `you`, tr: `Teşekkürler, iyi geceler.`, pl: `Dziękuję, dobranoc.`}]},{id: 3, title: `Pytanie o drogę`, scene: `Spacerujesz po Stambule i szukasz najbliższej stacji metra. Zaczepiasz lokalną osobę na ulicy i prosisz o wskazówki.`, lines: [{who: `you`, tr: `Pardon, metro nerede?`, pl: `Przepraszam, gdzie jest metro?`},{who: `them`, tr: `Metro yakın, düz gidin.`, pl: `Metro jest blisko, proszę iść prosto.`},{who: `you`, tr: `Sonra sağa mı?`, pl: `Potem w prawo?`},{who: `them`, tr: `Evet, sonra sağa dönün.`, pl: `Tak, potem proszę skręcić w prawo.`},{who: `you`, tr: `Kaç dakika?`, pl: `Ile minut?`},{who: `them`, tr: `Beş dakika.`, pl: `Pięć minut.`},{who: `you`, tr: `İstasyon büyük mü?`, pl: `Czy stacja jest duża?`},{who: `them`, tr: `Evet, büyük ve karşıda.`, pl: `Tak, jest duża i naprzeciwko.`},{who: `you`, tr: `Tekrar eder misiniz?`, pl: `Czy może pan/pani powtórzyć?`},{who: `them`, tr: `Düz gidin, sonra sağa dönün.`, pl: `Proszę iść prosto, potem skręcić w prawo.`},{who: `you`, tr: `Çok teşekkürler.`, pl: `Bardzo dziękuję.`},{who: `them`, tr: `Rica ederim.`, pl: `Proszę bardzo.`}]},{id: 4, title: `Kolacja w restauracji`, scene: `Jesteś w restauracji w Antalyi i chcesz zamówić kolację. Pytasz o polecane danie, ostrość i rachunek.`, lines: [{who: `them`, tr: `Merhaba, menü buyurun.`, pl: `Dzień dobry, oto menu.`},{who: `you`, tr: `Teşekkürler, ne tavsiye edersiniz?`, pl: `Dziękuję, co pan/pani poleca?`},{who: `them`, tr: `Balık çok güzel.`, pl: `Ryba jest bardzo dobra.`},{who: `you`, tr: `Balık istiyorum, acı değil lütfen.`, pl: `Chcę rybę, nieostre proszę.`},{who: `them`, tr: `Tabii, salata ister misiniz?`, pl: `Oczywiście, czy chce pan/pani sałatkę?`},{who: `you`, tr: `Evet, bir salata lütfen.`, pl: `Tak, jedną sałatkę poproszę.`},{who: `them`, tr: `İçecek ne olsun?`, pl: `Co do picia?`},{who: `you`, tr: `Bir su alabilir miyim?`, pl: `Czy mogę dostać wodę?`},{who: `them`, tr: `Tabii.`, pl: `Oczywiście.`},{who: `you`, tr: `Hesap lütfen.`, pl: `Rachunek poproszę.`},{who: `them`, tr: `Hemen getiriyorum.`, pl: `Zaraz przynoszę.`},{who: `you`, tr: `Kartla ödeyebilir miyim?`, pl: `Czy mogę zapłacić kartą?`}]},{id: 5, title: `Kupowanie biletu na transport`, scene: `Stoisz przy kasie biletowej w Ankarze. Chcesz kupić bilet i dowiedzieć się, którą linią jechać.`, lines: [{who: `them`, tr: `Merhaba, nasıl yardımcı olabilirim?`, pl: `Dzień dobry, jak mogę pomóc?`},{who: `you`, tr: `Bir bilet lütfen.`, pl: `Jeden bilet poproszę.`},{who: `them`, tr: `Nereye gidiyorsunuz?`, pl: `Dokąd pan/pani jedzie?`},{who: `you`, tr: `Müze istasyonuna gidiyorum.`, pl: `Jadę na stację Muzeum.`},{who: `them`, tr: `İki numaralı hat.`, pl: `Linia numer dwa.`},{who: `you`, tr: `Aktarma var mı?`, pl: `Czy jest przesiadka?`},{who: `them`, tr: `Hayır, direkt gidiyor.`, pl: `Nie, jedzie bezpośrednio.`},{who: `you`, tr: `Ne kadar?`, pl: `Ile kosztuje?`},{who: `them`, tr: `On beş lira.`, pl: `Piętnaście lir.`},{who: `you`, tr: `Kartla ödeyebilir miyim?`, pl: `Czy mogę zapłacić kartą?`},{who: `them`, tr: `Evet, kart burada.`, pl: `Tak, karta tutaj.`},{who: `you`, tr: `Teşekkürler.`, pl: `Dziękuję.`}]},{id: 6, title: `Zakupy na bazarze`, scene: `Jesteś na bazarze w Izmirze i kupujesz owoce oraz przyprawy. Chcesz zapytać o świeżość, cenę i małą zniżkę.`, lines: [{who: `them`, tr: `Buyurun, taze meyve var.`, pl: `Proszę, są świeże owoce.`},{who: `you`, tr: `Merhaba, bu taze mi?`, pl: `Dzień dobry, czy to jest świeże?`},{who: `them`, tr: `Evet, bugün geldi.`, pl: `Tak, przyszło dzisiaj.`},{who: `you`, tr: `Yarım kilo lütfen.`, pl: `Pół kilo poproszę.`},{who: `them`, tr: `Başka bir şey?`, pl: `Coś jeszcze?`},{who: `you`, tr: `Baharat var mı?`, pl: `Czy są przyprawy?`},{who: `them`, tr: `Evet, burada.`, pl: `Tak, tutaj.`},{who: `you`, tr: `Ne kadar?`, pl: `Ile kosztuje?`},{who: `them`, tr: `Yüz lira.`, pl: `Sto lir.`},{who: `you`, tr: `Biraz indirim var mı?`, pl: `Czy jest mała zniżka?`},{who: `them`, tr: `Tamam, doksan lira olsun.`, pl: `Dobrze, niech będzie dziewięćdziesiąt lir.`},{who: `you`, tr: `Teşekkürler, alıyorum.`, pl: `Dziękuję, biorę.`}]},{id: 7, title: `W aptece`, scene: `W Bodrum boli cię głowa i szukasz apteki. Wchodzisz do apteki i prosisz o odpowiednie lekarstwo.`, lines: [{who: `them`, tr: `Merhaba, geçmiş olsun.`, pl: `Dzień dobry, życzę zdrowia.`},{who: `you`, tr: `Merhaba, başım ağrıyor.`, pl: `Dzień dobry, boli mnie głowa.`},{who: `them`, tr: `Ateşiniz var mı?`, pl: `Czy ma pan/pani gorączkę?`},{who: `you`, tr: `Hayır, ateşim yok.`, pl: `Nie, nie mam gorączki.`},{who: `them`, tr: `Alerjiniz var mı?`, pl: `Czy ma pan/pani alergię?`},{who: `you`, tr: `Evet, fındık alerjim var.`, pl: `Tak, mam alergię na orzechy laskowe.`},{who: `them`, tr: `Tamam, bu ilacı alabilirsiniz.`, pl: `Dobrze, może pan/pani wziąć to lekarstwo.`},{who: `you`, tr: `Nasıl kullanmalıyım?`, pl: `Jak powinienem/powinnam używać?`},{who: `them`, tr: `Günde iki kez.`, pl: `Dwa razy dziennie.`},{who: `you`, tr: `Ne kadar?`, pl: `Ile kosztuje?`},{who: `them`, tr: `Elli lira.`, pl: `Pięćdziesiąt lir.`},{who: `you`, tr: `Teşekkürler.`, pl: `Dziękuję.`}]},{id: 8, title: `Mała rozmowa z lokalną osobą`, scene: `Siedzisz przy wspólnym stoliku w kawiarni w Kapadocji. Lokalna osoba zaczyna rozmowę, a ty mówisz trochę po turecku.`, lines: [{who: `them`, tr: `Merhaba, nerelisiniz?`, pl: `Dzień dobry, skąd pan/pani jest?`},{who: `you`, tr: `Merhaba, Polonya’dan geldim.`, pl: `Dzień dobry, przyjechałem/przyjechałam z Polski.`},{who: `them`, tr: `Türkiye’yi seviyor musunuz?`, pl: `Czy lubi pan/pani Turcję?`},{who: `you`, tr: `Evet, çok seviyorum.`, pl: `Tak, bardzo lubię.`},{who: `them`, tr: `Kapadokya güzel mi?`, pl: `Czy Kapadocja jest piękna?`},{who: `you`, tr: `Evet, çok güzel.`, pl: `Tak, bardzo piękna.`},{who: `them`, tr: `Türkçe biliyor musunuz?`, pl: `Czy zna pan/pani turecki?`},{who: `you`, tr: `Türkçe az biliyorum.`, pl: `Znam trochę turecki.`},{who: `them`, tr: `Çok iyi konuşuyorsunuz.`, pl: `Mówi pan/pani bardzo dobrze.`},{who: `you`, tr: `Teşekkürler, yavaş konuşur musunuz?`, pl: `Dziękuję, czy może pan/pani mówić wolniej?`},{who: `them`, tr: `Tabii, memnuniyetle.`, pl: `Oczywiście, z przyjemnością.`},{who: `you`, tr: `Sizinle tanışmak güzel.`, pl: `Miło pana/panią poznać.`}]}];